    public void test_TC13() {
        // GIVEN: root with nested <span><a/><b/></span>, so 'b' has a sibling and is at depth 2
        Element root = Jsoup.parse("<div><span><a/><b/></span></div>").body().child(0);
        List<String> log = new ArrayList<>();
        NodeVisitor visitor = new NodeVisitor() {
            @Override
            public void head(Node n, int d) {
                // replace 'b' at depth 2 to force branch B8: origSize equals after replace
                if ("b".equals(n.nodeName()) && d == 2) {
                    Element replacement = new Element("c");
