            }

            @Override
            public void tail(Node n, int d) {
                log.add("t:" + n.nodeName() + ":" + d);
            }
        };

        // WHEN: traverse should visit replacement 'c' at same depth
        NodeTraversor.traverse(visitor, (Node) root);

        // THEN: ensure 'c' was visited in head at depth 2
        assertTrue(log.contains("h:c:2"), "Expected replacement node 'c' to be visited at depth 2");
    }

